INSERT INTO `courses` VALUES (6,'aprende-dirigir-ia','Aprende a dirigir la IA como si fuera tu mejor empleado','Aprender a comunicarse con la IA de forma estratégica. Curso con plantilla SmartPrompt Framework, casos prácticos, grabación y certificado','/uploads/1784296468560_tuempleado_ia3.png',149.00,49.00,NULL,4,1,'2026-07-16 20:42:50','2026-07-17 13:54:32',0,75,NULL,50,50),(7,'chatgpt-oficina','ChatGPT para la Oficina','Ahorrar tiempo en tareas diarias de oficina. Curso con biblioteca de plantillas, casos prácticos, grabación y certificado',NULL,199.00,69.00,NULL,4,1,'2026-07-16 20:42:50','2026-07-16 20:42:50',0,75,NULL,50,50),(8,'excel-ia-profesionales','Excel + IA para Profesionales','Resolver tareas de Excel con IA. Curso con 50 casos prácticos, plantillas Excel, grabación y certificado',NULL,229.00,79.00,NULL,4,1,'2026-07-16 20:42:50','2026-07-16 20:42:50',0,75,NULL,50,50),(9,'datos-decisiones-ia','Cómo convertir datos en decisiones usando IA','Transformar datos en decisiones estratégicas. Curso con plantilla de dashboard ejecutivo, casos de análisis, grabación y certificado',NULL,299.00,99.00,NULL,4,1,'2026-07-16 20:42:50','2026-07-16 20:42:50',0,75,NULL,50,50),(11,'automatiza-tu-trabajo-sin-programar-con-n8n','Automatiza tu trabajo sin programar con n8n','Aprende a automatizar tareas de oficina sin necesidad de programar utilizando n8n, una herramienta potente y fácil de usar.','/uploads/1784297801476_curso_automatiza_conia.png',299.00,99.00,NULL,4,1,'2026-07-17 14:16:19','2026-07-17 14:16:58',0,75,NULL,50,50);
