/*!40000 ALTER TABLE `modules` DISABLE KEYS */;
INSERT INTO `modules` VALUES (30,6,'Introduccion','Hace apenas unos años, tener un equipo de expertos era un privilegio reservado para las grandes empresas.\n\nSi necesitabas un abogado, contratabas un abogado.\n\nSi necesitabas un diseñador, contratabas un diseñador.\n\nSi necesitabas un programador, contratabas un programador.\n\nCada nuevo problema significaba buscar otra persona.\n\nHoy eso cambió.\n\nPor primera vez en la historia, cualquier persona tiene acceso a una inteligencia capaz de ayudarte en prácticamente cualquier disciplina.\n\nPero existe un problema.\n\nLa mayoría de las personas usa la IA como si fuera Google.\n\nHace preguntas rápidas.\n\nObtiene respuestas superficiales.\n\nY termina pensando que \"la IA no sirve tanto\".\n\nLa realidad es otra.\n\nLa IA puede convertirse en el mejor empleado que hayas tenido.\n\nUn empleado que nunca duerme.\n\nQue conoce miles de profesiones.\n\nQue aprende tu forma de trabajar.\n\nY que puede ayudarte a pensar, crear, analizar, escribir, programar, investigar y tomar decisiones.\n\nPero, como cualquier empleado…\n\nNecesita un buen director.\n\nY ese director eres tú.\n\nEste curso no trata de aprender una herramienta.\n\nNo trata de memorizar comandos.\n\nNo trata de usar ChatGPT.\n\nEste curso trata de desarrollar una nueva habilidad profesional:\n\nAprender a dirigir inteligencia artificial.\n\nPorque durante los próximos años habrá una enorme diferencia entre quienes simplemente usan IA…\n\nY quienes saben dirigirla para multiplicar su productividad.\n\nEse será el objetivo de este curso.\n\nAl terminar, dejarás de ver la IA como un chatbot.\n\nY comenzarás a verla como el mejor empleado que jamás has tenido.',0,'2026-07-16 20:49:08'),(31,6,'Aprende a dirigir la IA como un profesional','',1,'2026-07-16 20:49:08'),(34,11,'Introducción a la Automatización','Conceptos básicos sobre la automatización y su importancia en el trabajo de oficina.',1,'2026-07-17 14:16:19'),(35,11,'Introducción a n8n','Conoce n8n y cómo puede ayudarte a automatizar tus tareas.',2,'2026-07-17 14:16:19'),(36,11,'Creando tu Primer Flujo','Aprende a crear un flujo básico en n8n.',3,'2026-07-17 14:16:19'),(37,11,'Integraciones Comunes','Aprende a integrar n8n con otras herramientas populares.',4,'2026-07-17 14:16:19'),(38,11,'Casos de Uso Prácticos','Explora ejemplos prácticos de automatización en el trabajo de oficina.',5,'2026-07-17 14:16:19'),(39,11,'Conclusiones y Próximos Pasos','Reflexiones finales y recursos adicionales para seguir aprendiendo.',6,'2026-07-17 14:16:19');
